css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #faf6ef; color: #2c2418; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; border-bottom: 1px solid #ece3d4; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #a8987f; text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #b45309; }
.cart-icon { font-size: 15px; font-weight: 700; cursor: pointer; }
.hero { padding: 60px; background: linear-gradient(135deg, #fef3e2, #fdf6ed); }
.hero-text { max-width: 580px; }
.badge { display: inline-block; color: #b45309; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 20px; }
.hero h1 { font-size: 44px; font-weight: 800; line-height: 1.3; margin-bottom: 16px; }
.hero h1 span { color: #b45309; }
.hero p { color: #a8987f; font-size: 15px; line-height: 1.7; }
.products { padding: 50px 60px; }
.filter-row { display: flex; gap: 10px; margin-bottom: 30px; flex-wrap: wrap; }
.filter { background: white; border: 1px solid #ece3d4; color: #a8987f; padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: #b45309; color: white; border-color: #b45309; }
.product-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(180px, 1fr)); gap: 24px; }
.product-card { cursor: pointer; }
.book-cover { aspect-ratio: 2/3; border-radius: 6px; display: flex; align-items: center; justify-content: center; font-size: 44px; margin-bottom: 12px; box-shadow: 0 12px 24px rgba(0,0,0,0.08); color: white; transition: 0.2s; }
.product-card:hover .book-cover { transform: translateY(-4px); }
.product-card h3 { font-size: 14px; font-weight: 700; margin-bottom: 4px; line-height: 1.4; }
.author { display: block; font-size: 12.5px; color: #a8987f; margin-bottom: 6px; }
.price { color: #b45309; font-weight: 800; font-size: 14px; }
.cart-drawer { position: fixed; top: 0; right: -380px; width: 360px; height: 100%; background: white; box-shadow: -10px 0 40px rgba(0,0,0,0.1); z-index: 20; transition: right 0.3s; display: flex; flex-direction: column; }
.cart-drawer.open { right: 0; }
.cart-header { display: flex; justify-content: space-between; align-items: center; padding: 24px; border-bottom: 1px solid #ece3d4; }
.cart-header h2 { font-size: 18px; font-weight: 800; }
.cart-header button { background: none; border: none; font-size: 18px; cursor: pointer; }
.cart-items { flex: 1; overflow-y: auto; padding: 16px 24px; display: flex; flex-direction: column; gap: 14px; }
.cart-item { display: flex; gap: 14px; align-items: center; }
.cart-item-img { width: 44px; height: 64px; border-radius: 4px; display: flex; align-items: center; justify-content: center; font-size: 18px; flex-shrink: 0; color: white; }
.cart-item-info { flex: 1; }
.cart-item-info h4 { font-size: 13.5px; font-weight: 700; }
.cart-item-info span { font-size: 12.5px; color: #a8987f; }
.remove-btn { background: none; border: none; color: #ccc; font-size: 14px; cursor: pointer; }
.cart-footer { padding: 24px; border-top: 1px solid #ece3d4; }
.cart-total { display: flex; justify-content: space-between; font-size: 16px; font-weight: 800; margin-bottom: 16px; }
.btn-primary.full { width: 100%; background: #b45309; color: white; border: none; padding: 15px; border-radius: 10px; font-size: 14px; font-weight: 700; cursor: pointer; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.3); display: none; z-index: 19; }
.overlay.show { display: block; }
@media (max-width: 900px) { .navbar, .hero, .products { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 30px; } .cart-drawer { width: 100%; right: -100%; } }

