const products = [
  { id: 1, name: 'Kıyının Öbür Tarafı', author: 'Cem Yıldız', cat: 'fiction', price: 145, emoji: '📕', color: '#b45309' },
  { id: 2, name: 'Atomic Habits', author: 'James Clear', cat: 'selfhelp', price: 165, emoji: '📗', color: '#65a30d' },
  { id: 3, name: 'Marsta Bir Kış', author: 'A. Weir', cat: 'scifi', price: 185, emoji: '📘', color: '#1d4ed8' },
  { id: 4, name: 'Gölgelerin Şehri', author: 'Cem Yıldız', cat: 'fiction', price: 155, emoji: '📙', color: '#c2410c' },
  { id: 5, name: 'Derin Çalışma', author: 'Cal Newport', cat: 'selfhelp', price: 175, emoji: '📔', color: '#7c3aed' },
  { id: 6, name: 'Yıldız Tozu Günlükleri', author: 'N. Kara', cat: 'scifi', price: 195, emoji: '📒', color: '#0e7490' },
  { id: 7, name: 'Sessiz Sokaklar', author: 'Elif Aksoy', cat: 'fiction', price: 135, emoji: '📕', color: '#9d174d' },
  { id: 8, name: 'Odaklanma Sanatı', author: 'B. Türk', cat: 'selfhelp', price: 145, emoji: '📗', color: '#15803d' }
];

let cart = [];

function renderProducts(filter) {
  const grid = document.getElementById('productGrid');
  grid.innerHTML = '';
  products
    .filter(p => filter === 'all' || p.cat === filter)
    .forEach(p => {
      const card = document.createElement('div');
      card.className = 'product-card';
      card.innerHTML = `
        <div class="book-cover" style="background:${p.color}">${p.emoji}</div>
        <h3>${p.name}</h3>
        <span class="author">${p.author}</span>
        <span class="price">₺${p.price}</span>
      `;
      card.addEventListener('click', () => addToCart(p));
      grid.appendChild(card);
    });
}

function filterProducts(btn, filter) {
  document.querySelectorAll('.filter').forEach(f => f.classList.remove('active'));
  btn.classList.add('active');
  renderProducts(filter);
}

function addToCart(product) {
  cart.push(product);
  updateCart();
  toggleCart(true);
}

function removeFromCart(index) {
  cart.splice(index, 1);
  updateCart();
}

function updateCart() {
  document.getElementById('cartCount').textContent = cart.length;
  const itemsContainer = document.getElementById('cartItems');
  itemsContainer.innerHTML = '';
  let total = 0;
  cart.forEach((item, i) => {
    total += item.price;
    const div = document.createElement('div');
    div.className = 'cart-item';
    div.innerHTML = `
      <div class="cart-item-img" style="background:${item.color}">${item.emoji}</div>
      <div class="cart-item-info"><h4>${item.name}</h4><span>₺${item.price}</span></div>
      <button class="remove-btn" onclick="removeFromCart(${i})">✕</button>
    `;
    itemsContainer.appendChild(div);
  });
  document.getElementById('cartTotal').textContent = `₺${total}`;
}

function toggleCart(forceOpen) {
  const drawer = document.getElementById('cartDrawer');
  const overlay = document.getElementById('overlay');
  const shouldOpen = forceOpen !== undefined ? forceOpen : !drawer.classList.contains('open');
  drawer.classList.toggle('open', shouldOpen);
  overlay.classList.toggle('show', shouldOpen);
}

renderProducts('all');
